 using System;
 using System.Runtime.CompilerServices;
 using System.Runtime.InteropServices;
 using System.Runtime.Intrinsics;

 namespace ByteBitReverse;

 public class BitReverser
 {
     public static void ReverseInPlace(Span<byte> data)
     {
         ref var src = ref MemoryMarshal.GetReference(data);
         uint i = 0;
         uint length = (uint)data.Length;

         // LUT: index by 4-bit nibble → bit-reversed nibble shifted to high position.
         // Entry[n] = reverse4(n) << 4.  Entry[n] in low position = reverse4(n).
         // reverse4: 0→0, 1→8, 2→4, 3→C, 4→2, 5→A, 6→6, 7→E,
         //           8→1, 9→9, A→5, B→D, C→3, D→B, E→7, F→F
         var nibbleReverseLut = Vector128.Create(
             (byte)0x0, 0x8, 0x4, 0xC, 0x2, 0xA, 0x6, 0xE,
                   0x1, 0x9, 0x5, 0xD, 0x3, 0xB, 0x7, 0xF);
         var nibbleMask = Vector128.Create((byte)0x0F);

         if (Vector512.IsHardwareAccelerated && Vector512<byte>.IsSupported)
         {
             var lower256 = Vector256.Create(nibbleReverseLut, nibbleReverseLut);
             var lut512 = Vector512.Create(lower256, lower256);
             var mask512 = Vector512.Create((byte)0x0F);
             uint vec512Count = (uint)Vector512<byte>.Count;
             while (i + vec512Count <= length)
             {
                 var vec = Vector512.LoadUnsafe(ref src, i);
                 var lo = vec & mask512;
                 var hi = Vector512.ShiftRightLogical(vec.AsUInt16(), 4).AsByte() & mask512;
                 var reversedLo = Vector512.Shuffle(lut512, lo);
                 var reversedHi = Vector512.Shuffle(lut512, hi);
                 var result = Vector512.ShiftLeft(reversedLo.AsUInt16(), 4).AsByte() | reversedHi;
                 result.StoreUnsafe(ref src, i);
